<script>document.addEventListener('DOMContentLoaded',()=>{const modal=document.getElementById('admin-modal'),open=document.getElementById('open-admin-modal'),close=document.getElementById('close-admin-modal'),cancel=document.getElementById('cancel-admin-modal'),password=document.getElementById('admin-password'),toggle=document.getElementById('toggle-admin-password');const set=(visible)=>{modal.classList.toggle('hidden',!visible);document.body.classList.toggle('overflow-hidden',visible);if(visible)setTimeout(()=>modal.querySelector('[name=email]')?.focus(),60)};open?.addEventListener('click',()=>set(true));[close,cancel].forEach(button=>button?.addEventListener('click',()=>set(false)));modal?.addEventListener('click',(event)=>{if(event.target===modal)set(false)});document.addEventListener('keydown',(event)=>{if(event.key==='Escape')set(false)});toggle?.addEventListener('click',()=>{const visible=password.type==='password';password.type=visible?'text':'password';toggle.innerHTML=visible?'<i class="fa-regular fa-eye-slash"></i>':'<i class="fa-regular fa-eye"></i>'});if(@json($errors->any()))set(true)});</script>
